class Solution:
    def reachNumber(self, target: int) -> int:
        target = abs(target)
        k = 0
        sum_total = 0
        while sum_total < target:
            k += 1
            sum_total += k
        if (sum_total - target) % 2 == 0:
            return k
        else:
            if (k + 1) % 2 == 1:
                return k + 1
            else:
                return k + 2

